import ProductCard, { type Product } from "./ProductCard";
import useScrollAnimation from "@/hooks/use-scroll-animation";

interface ProductGridProps {
  products: Product[];
}

const ProductGrid = ({ products }: ProductGridProps) => {
  const gridRef = useScrollAnimation();

  if (products.length === 0) {
    return (
      <div className="container mx-auto px-4 py-16">
        <div className="text-center">
          <p className="text-xl text-muted-foreground">No products found in this category.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div 
        ref={gridRef.ref}
        className={`grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 transition-all duration-700 ${
          gridRef.isVisible ? 'animate-fade-in' : 'scroll-hidden'
        }`}
      >
        {products.map((product, index) => (
          <div
            key={product.id}
            className={`transition-all duration-700 ${
              gridRef.isVisible ? `animate-scale-in animate-stagger-${(index % 6) + 1}` : 'scroll-hidden-scale'
            }`}
          >
            <ProductCard product={product} />
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductGrid;

import React, { type ReactNode } from 'react';
import { useScrollAnimation } from '../../hooks/useScrollAnimation';

interface ScrollRevealProps {
  children: ReactNode;
  className?: string;
  direction?: 'up' | 'down' | 'left' | 'right';
  delay?: number;
  duration?: number;
  distance?: number;
}

export const ScrollReveal: React.FC<ScrollRevealProps> = ({
  children,
  className = '',
  direction = 'up',
  delay = 0,
  duration = 1,
  distance = 50
}) => {
  const { elementRef } = useScrollAnimation();

  React.useEffect(() => {
    // Fallback timeout to ensure content is always visible
    const fallbackTimeout = setTimeout(() => {
      if (elementRef.current) {
        elementRef.current.style.opacity = '1';
        elementRef.current.style.transform = 'translate3d(0, 0, 0)';
      }
    }, 100);

    const animateElement = async () => {
      try {
        const { gsap } = await import('gsap');
        const { ScrollTrigger } = await import('gsap/ScrollTrigger');
        
        gsap.registerPlugin(ScrollTrigger);

        if (!elementRef.current) return;

        // Check for reduced motion
        const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
        
        if (prefersReducedMotion) {
          gsap.set(elementRef.current, { opacity: 1, x: 0, y: 0 });
          clearTimeout(fallbackTimeout);
          return;
        }

        // Direction mappings
        const directions = {
          up: { x: 0, y: distance },
          down: { x: 0, y: -distance },
          left: { x: distance, y: 0 },
          right: { x: -distance, y: 0 }
        };

        const from = directions[direction];

        // Set initial state only after GSAP is ready
        gsap.set(elementRef.current, {
          opacity: 0,
          x: from.x,
          y: from.y,
          scale: 0.98
        });

        gsap.to(elementRef.current, {
          opacity: 1,
          x: 0,
          y: 0,
          scale: 1,
          duration,
          delay,
          ease: "power2.out",
          scrollTrigger: {
            trigger: elementRef.current,
            start: "top 95%",
            toggleActions: "play none none reverse"
          }
        });

        clearTimeout(fallbackTimeout);
      } catch (error) {
        console.warn('ScrollReveal animation failed:', error);
        // Fallback
        if (elementRef.current) {
          elementRef.current.style.opacity = '1';
          elementRef.current.style.transform = 'translate3d(0, 0, 0)';
        }
        clearTimeout(fallbackTimeout);
      }
    };

    animateElement();

    return () => {
      clearTimeout(fallbackTimeout);
    };
  }, [direction, delay, duration, distance]);

  return (
    <div ref={elementRef} className={`opacity-100 ${className}`} style={{ opacity: 1 }}>
      {children}
    </div>
  );
};

import React, { type ReactNode, useEffect, useRef } from 'react';

interface SectionTransitionProps {
  children: ReactNode;
  className?: string;
  fromGradient?: string;
  toGradient?: string;
  type?: 'fade' | 'scale' | 'slide' | 'mask';
}

export const SectionTransition: React.FC<SectionTransitionProps> = ({
  children,
  className = '',
  fromGradient = 'from-black to-gray-900',
  toGradient = 'from-gray-900 to-black',
  type = 'fade'
}) => {
  const sectionRef = useRef<HTMLDivElement>(null);
  const fromLayerRef = useRef<HTMLDivElement | null>(null);
  const toLayerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    // Ensure content is visible immediately
    const ensureVisibility = () => {
      if (sectionRef.current) {
        const content = Array.from(sectionRef.current.children);
        content.forEach((child: any) => {
          if (child.style) {
            child.style.opacity = '1';
            child.style.transform = 'translate3d(0, 0, 0)';
          }
        });
      }
    };

    // Immediate visibility
    ensureVisibility();

    const animateTransition = async () => {
      try {
        const { gsap } = await import('gsap');
        const { ScrollTrigger } = await import('gsap/ScrollTrigger');
        
        gsap.registerPlugin(ScrollTrigger);

        if (!sectionRef.current) return;

        // Check for reduced motion
        const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
        if (prefersReducedMotion) {
          ensureVisibility();
          return;
        }

        const section = sectionRef.current;
        
        // Create background layers for gradient transition
        const fromLayer = document.createElement('div');
        const toLayer = document.createElement('div');
        
        fromLayer.className = `absolute inset-0 bg-gradient-to-b ${fromGradient}`;
        toLayer.className = `absolute inset-0 bg-gradient-to-b ${toGradient}`;
        
        fromLayer.style.zIndex = '0';
        toLayer.style.zIndex = '0';
        toLayer.style.opacity = '0';
        fromLayer.style.pointerEvents = 'none';
        toLayer.style.pointerEvents = 'none';
        
        section.style.position = 'relative';
        section.style.isolation = 'isolate';
        section.insertBefore(fromLayer, section.firstChild);
        section.insertBefore(toLayer, section.firstChild);
        
        fromLayerRef.current = fromLayer;
        toLayerRef.current = toLayer;

        // Animate gradient transition
        gsap.to(toLayer, {
          opacity: 1,
          duration: 2,
          ease: "power2.inOut",
          scrollTrigger: {
            trigger: section,
            start: "top 70%",
            end: "bottom 30%",
            scrub: 1
          }
        });

        // Get content elements, excluding background layers
        const content = Array.from(section.children).filter(child => 
          child !== fromLayer && child !== toLayer
        );

        // Only animate if elements exist and are visible
        if (content.length > 0) {
          switch (type) {
            case 'scale':
              gsap.fromTo(content, 
                { scale: 0.95 },
                { 
                  scale: 1,
                  duration: 1,
                  ease: "power2.out",
                  scrollTrigger: {
                    trigger: section,
                    start: "top 90%",
                    toggleActions: "play none none reverse"
                  }
                }
              );
              break;
              
            case 'slide':
              gsap.fromTo(content,
                { x: 30 },
                {
                  x: 0,
                  duration: 0.8,
                  ease: "power2.out",
                  stagger: 0.1,
                  scrollTrigger: {
                    trigger: section,
                    start: "top 90%",
                    toggleActions: "play none none reverse"
                  }
                }
              );
              break;
              
            default: // fade - keep content visible, just add subtle entrance
              gsap.fromTo(content,
                { y: 20 },
                {
                  y: 0,
                  duration: 0.6,
                  ease: "power2.out",
                  stagger: 0.05,
                  scrollTrigger: {
                    trigger: section,
                    start: "top 95%",
                    toggleActions: "play none none reverse"
                  }
                }
              );
          }
        }
      } catch (error) {
        console.warn('Section transition animation failed:', error);
        ensureVisibility();
      }
    };

    // Small delay to ensure DOM is ready
    const timeoutId = window.setTimeout(animateTransition, 10);

    // Cleanup on unmount
    return () => {
      window.clearTimeout(timeoutId);
      try {
        const section = sectionRef.current;
        if (section && fromLayerRef.current && section.contains(fromLayerRef.current)) {
          section.removeChild(fromLayerRef.current);
        }
        if (section && toLayerRef.current && section.contains(toLayerRef.current)) {
          section.removeChild(toLayerRef.current);
        }
        // Attempt to kill ScrollTriggers for this section
        import('gsap/ScrollTrigger').then(({ ScrollTrigger }) => {
          ScrollTrigger.getAll().forEach(tr => {
            if ((tr.vars?.trigger as Element) === section) tr.kill();
          });
        }).catch(() => {});
      } catch (e) {
        // ignore cleanup errors
      }
    };
  }, [fromGradient, toGradient, type]);

  return (
    <div ref={sectionRef} className={`relative overflow-hidden ${className}`}>
      <div className="relative z-10">
        {children}
      </div>
    </div>
  );
};

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "../../lib/utils"

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary:
          "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive:
          "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  )
}

export { Badge, badgeVariants }

