import { createContext, useContext, useState, useEffect } from 'react';
import type { ReactNode } from 'react';
import { blogsData as initialBlogsData } from '../data/blogs';

export interface BlogPost {
    id: string;
    title: string;
    excerpt: string;
    content: string;
    image: string;
    date: string;
    readTime: string;
    category: string;
    author: {
        name: string;
        avatar: string;
    };
}

interface BlogContextType {
    blogs: BlogPost[];
    addBlog: (blog: Omit<BlogPost, 'id' | 'date' | 'author'>) => void;
    updateBlog: (id: string, updatedBlog: Partial<BlogPost>) => void;
    deleteBlog: (id: string) => void;
    getBlog: (id: string) => BlogPost | undefined;
}

const BlogContext = createContext<BlogContextType | undefined>(undefined);

export const BlogProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [blogs, setBlogs] = useState<BlogPost[]>([]);

    // Initialize blogs from localStorage or fallback to static data
    useEffect(() => {
        const storedBlogs = localStorage.getItem('tradingSmartBlogs');
        if (storedBlogs) {
            setBlogs(JSON.parse(storedBlogs));
        } else {
            setBlogs(initialBlogsData);
            localStorage.setItem('tradingSmartBlogs', JSON.stringify(initialBlogsData));
        }
    }, []);

    // Sync to localStorage whenever blogs change
    useEffect(() => {
        if (blogs.length > 0) {
            localStorage.setItem('tradingSmartBlogs', JSON.stringify(blogs));
        }
    }, [blogs]);

    const addBlog = (blogData: Omit<BlogPost, 'id' | 'date' | 'author'>) => {
        const newBlog: BlogPost = {
            ...blogData,
            id: blogData.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, ''),
            date: new Date().toLocaleDateString('en-US', {
                year: 'numeric',
                month: 'long',
                day: 'numeric'
            }),
            author: {
                name: "Admin User",
                avatar: "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=150&auto=format&fit=crop"
            }
        };
        setBlogs([newBlog, ...blogs]);
    };

    const updateBlog = (id: string, updatedFields: Partial<BlogPost>) => {
        setBlogs(blogs.map(blog => blog.id === id ? { ...blog, ...updatedFields } : blog));
    };

    const deleteBlog = (id: string) => {
        setBlogs(blogs.filter(blog => blog.id !== id));
    };

    const getBlog = (id: string) => {
        return blogs.find(blog => blog.id === id);
    };

    return (
        <BlogContext.Provider value={{ blogs, addBlog, updateBlog, deleteBlog, getBlog }}>
            {children}
        </BlogContext.Provider>
    );
};

export const useBlogs = () => {
    const context = useContext(BlogContext);
    if (!context) {
        throw new Error('useBlogs must be used within a BlogProvider');
    }
    return context;
};

import { useEffect, useRef, useState } from 'react';

interface UseScrollAnimationOptions {
  threshold?: number;
  rootMargin?: string;
  triggerOnce?: boolean;
}

export const useScrollAnimation = (options: UseScrollAnimationOptions = {}) => {
  const {
    threshold = 0.1,
    rootMargin = '0px 0px -50px 0px',
    triggerOnce = true
  } = options;

  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          if (triggerOnce) {
            observer.unobserve(entry.target);
          }
        } else if (!triggerOnce) {
          setIsVisible(false);
        }
      },
      {
        threshold,
        rootMargin,
      }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => {
      if (ref.current) {
        observer.unobserve(ref.current);
      }
    };
  }, [threshold, rootMargin, triggerOnce]);

  return { ref, isVisible };
};

export default useScrollAnimation;

import { useEffect, useRef, useCallback } from 'react';

interface ScrollAnimationOptions {
  trigger?: string;
  start?: string;
  end?: string;
  scrub?: boolean | number;
  pin?: boolean;
  onEnter?: () => void;
  onLeave?: () => void;
}

export const useScrollAnimation = (options: ScrollAnimationOptions = {}) => {
  const elementRef = useRef<HTMLDivElement>(null);
  const animationRef = useRef<any>(null);

  const createAnimation = useCallback(async () => {
    try {
      // Dynamically import GSAP to avoid SSR issues
      const { gsap } = await import('gsap');
      const { ScrollTrigger } = await import('gsap/ScrollTrigger');
      
      gsap.registerPlugin(ScrollTrigger);

      // Check for reduced motion preference
      const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
      
      if (prefersReducedMotion) {
        // Provide simple fade-in for accessibility
        if (elementRef.current) {
          gsap.set(elementRef.current, { opacity: 1, y: 0 });
        }
        return;
      }

      if (elementRef.current) {
        animationRef.current = gsap.fromTo(
          elementRef.current,
          { 
            opacity: 0, 
            y: 50,
            scale: 0.98
          },
          {
            opacity: 1,
            y: 0,
            scale: 1,
            duration: 1,
            ease: "power2.out",
            scrollTrigger: {
              trigger: elementRef.current,
              start: options.start || "top 80%",
              end: options.end || "bottom 20%",
              scrub: options.scrub || false,
              pin: options.pin || false,
              onEnter: options.onEnter,
              onLeave: options.onLeave,
              markers: false // Set to true for debugging
            }
          }
        );
      }
    } catch (error) {
      console.warn('GSAP animation failed:', error);
      // Fallback: ensure element is visible
      if (elementRef.current) {
        elementRef.current.style.opacity = '1';
        elementRef.current.style.transform = 'translateY(0)';
      }
    }
  }, [options]);

  useEffect(() => {
    // Ensure element is visible first
    if (elementRef.current) {
      elementRef.current.style.opacity = '1';
    }
    
    // Small delay to ensure DOM is ready
    const timeout = setTimeout(createAnimation, 10);

    return () => {
      clearTimeout(timeout);
      if (animationRef.current) {
        animationRef.current.kill();
      }
    };
  }, [createAnimation]);

  // Staggered animation for multiple children
  const staggerFadeIn = useCallback(async (selector: string, delay = 0.1) => {
    try {
      const { gsap } = await import('gsap');
      const { ScrollTrigger } = await import('gsap/ScrollTrigger');
      
      gsap.registerPlugin(ScrollTrigger);

      const elements = elementRef.current?.querySelectorAll(selector);
      if (!elements) return;

      gsap.fromTo(
        elements,
        { 
          opacity: 0, 
          y: 30,
          scale: 0.95
        },
        {
          opacity: 1,
          y: 0,
          scale: 1,
          duration: 0.8,
          stagger: delay,
          ease: "power2.out",
          scrollTrigger: {
            trigger: elementRef.current,
            start: "top 85%",
            toggleActions: "play none none reverse"
          }
        }
      );
    } catch (error) {
      console.warn('Stagger animation failed:', error);
    }
  }, []);

  return { elementRef, staggerFadeIn };
};

