import { useEffect, useState } from 'react';
import { Helmet } from 'react-helmet-async';
import { useParams, Link } from 'react-router-dom';
import { FaArrowLeft } from 'react-icons/fa';
import AiPredictionHeader from '../components/AiPredictionHeader';
import AiPredictionFooter from '../components/AiPredictionFooter';
import { blogsData } from '../data/blogs';
import { ScrollReveal } from '../components/ui/ScrollReveal';

const BlogDetailPage = () => {
    const { id } = useParams<{ id: string }>();
    const [blog, setBlog] = useState<typeof blogsData[0] | null>(null);

    useEffect(() => {
        const foundBlog = blogsData.find(b => b.id === id);
        setBlog(foundBlog || null);
        window.scrollTo(0, 0);
    }, [id]);

    if (!blog) {
        return (
            <div className="min-h-screen bg-black text-white flex flex-col justify-center items-center">
                <AiPredictionHeader />
                <h1 className="text-3xl font-bold mb-4">Blog Post Not Found</h1>
                <Link to="/blogs" className="text-cyan-400 hover:underline">Return to Blogs</Link>
                <AiPredictionFooter />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-black text-white font-sans selection:bg-cyan-500 selection:text-black flex flex-col">
            <Helmet>
                <title>{blog.title} | TradingSmart.AI</title>
                <meta name="description" content={blog.excerpt} />
            </Helmet>

            <AiPredictionHeader />

            {/* Blog Header */}
            <section className="pt-32 pb-12 px-4 relative overflow-hidden bg-zinc-950">
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-5 pointer-events-none"></div>
                <div className="container mx-auto max-w-4xl relative z-10">
                    <Link to="/blogs" className="inline-flex items-center text-sm text-gray-400 hover:text-cyan-400 mb-8 transition-colors">
                        <FaArrowLeft className="mr-2" /> Back to all articles
                    </Link>

                    <ScrollReveal>
                        <div className="mb-6 flex gap-3">
                            <span className="bg-cyan-500/10 text-cyan-400 text-xs font-bold px-3 py-1 rounded-full border border-cyan-500/20 uppercase tracking-wider">
                                {blog.category}
                            </span>
                            <span className="bg-white/5 text-gray-300 text-xs font-bold px-3 py-1 rounded-full border border-white/10 flex items-center">
                                {blog.readTime}
                            </span>
                        </div>
                        <h1 className="text-3xl md:text-5xl lg:text-6xl font-black mb-8 leading-tight tracking-tight">
                            {blog.title}
                        </h1>

                        <div className="flex items-center gap-4 py-6 border-y border-white/5 mb-8">
                            <img
                                src={blog.author.avatar}
                                alt={blog.author.name}
                                className="w-12 h-12 rounded-full border border-white/10"
                            />
                            <div>
                                <div className="text-white font-bold">{blog.author.name}</div>
                                <div className="text-gray-500 text-sm">{blog.date}</div>
                            </div>
                        </div>
                    </ScrollReveal>
                </div>
            </section>

            {/* Featured Image */}
            <section className="px-4 -mt-8 relative z-20">
                <div className="container mx-auto max-w-5xl">
                    <ScrollReveal delay={0.2}>
                        <div className="aspect-video w-full rounded-2xl overflow-hidden border border-white/10 shadow-2xl relative">
                            <img
                                src={blog.image}
                                alt={blog.title}
                                className="w-full h-full object-cover"
                            />
                        </div>
                    </ScrollReveal>
                </div>
            </section>

            {/* Blog Content */}
            <section className="py-20 px-4">
                <div className="container mx-auto max-w-3xl">
                    <ScrollReveal delay={0.3}>
                        <div
                            className="prose prose-invert prose-lg md:prose-xl max-w-none 
                            prose-headings:font-bold prose-headings:tracking-tight 
                            prose-h2:text-white prose-h2:mt-12 prose-h2:mb-6
                            prose-h3:text-gray-200 prose-h3:mt-8
                            prose-p:text-gray-300 prose-p:leading-relaxed prose-p:font-light
                            prose-a:text-cyan-400 hover:prose-a:text-cyan-300
                            prose-strong:text-white prose-strong:font-semibold
                            prose-ul:text-gray-300 prose-li:marker:text-cyan-500
                            prose-blockquote:border-l-cyan-500 prose-blockquote:bg-cyan-500/5 prose-blockquote:px-6 prose-blockquote:py-2 prose-blockquote:rounded-r-lg prose-blockquote:text-gray-300 prose-blockquote:font-light prose-blockquote:italic
                            [&_.ql-video]:w-full [&_.ql-video]:aspect-video [&_.ql-video]:rounded-xl"
                            dangerouslySetInnerHTML={{ __html: blog.content }}
                        />
                    </ScrollReveal>
                </div>
            </section>

            {/* CTA Section */}
            <section className="py-24 bg-zinc-950 border-t border-white/5 relative overflow-hidden">
                <div className="absolute inset-0 bg-linear-to-b from-transparent to-cyan-900/10 pointer-events-none"></div>
                <div className="container mx-auto px-4 max-w-4xl text-center relative z-10">
                    <ScrollReveal>
                        <h2 className="text-3xl md:text-5xl font-bold mb-6">Ready to trade smarter?</h2>
                        <p className="text-gray-400 text-lg mb-10 max-w-2xl mx-auto">
                            Join thousands of traders using our AI models to predict market movements before they happen.
                        </p>
                        <Link
                            to="/#pricing"
                            className="inline-flex bg-cyan-500 text-black hover:bg-cyan-400 font-bold px-10 py-5 rounded-full shadow-[0_0_30px_rgba(6,182,212,0.3)] transition-all hover:-translate-y-1 hover:shadow-[0_0_40px_rgba(6,182,212,0.5)]"
                        >
                            View Subscription Plans
                        </Link>
                    </ScrollReveal>
                </div>
            </section>

            <AiPredictionFooter />
        </div>
    );
};

export default BlogDetailPage;

import { useState, useEffect } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { useBlogs } from '../../context/BlogContext';
import { FaArrowLeft, FaSave, FaImage, FaAlignLeft } from 'react-icons/fa';
import { AiOutlineLoading3Quarters } from 'react-icons/ai';
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css'; // ES6

const BlogEditor = () => {
    const { id } = useParams<{ id: string }>();
    const isEditing = Boolean(id);
    const { getBlog, addBlog, updateBlog } = useBlogs();
    const navigate = useNavigate();

    const [isLoading, setIsLoading] = useState(false);
    const [formData, setFormData] = useState({
        title: '',
        excerpt: '',
        content: '',
        image: '',
        category: '',
        readTime: '5 min read'
    });

    useEffect(() => {
        if (isEditing && id) {
            const existingBlog = getBlog(id);
            if (existingBlog) {
                setFormData({
                    title: existingBlog.title,
                    excerpt: existingBlog.excerpt,
                    content: existingBlog.content,
                    image: existingBlog.image,
                    category: existingBlog.category,
                    readTime: existingBlog.readTime
                });
            } else {
                // If ID is not found, redirect to dashboard
                navigate('/admin/dashboard');
            }
        }
    }, [id, isEditing, getBlog, navigate]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleContentChange = (value: string) => {
        setFormData(prev => ({ ...prev, content: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        // Simulate network delay
        setTimeout(() => {
            if (isEditing && id) {
                updateBlog(id, formData);
            } else {
                addBlog(formData);
            }
            setIsLoading(false);
            navigate('/admin/dashboard');
        }, 600);
    };

    return (
        <div className="max-w-4xl space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <Link
                        to="/admin/dashboard"
                        className="p-2 bg-zinc-900 hover:bg-zinc-800 text-gray-400 hover:text-white rounded-lg transition-colors border border-white/5"
                    >
                        <FaArrowLeft />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight text-white">
                            {isEditing ? 'Edit Blog Post' : 'Create New Blog Post'}
                        </h1>
                        <p className="text-gray-500 text-xs mt-1">
                            {isEditing ? `Editing ID: ${id}` : 'Fill in the details below to publish a new article.'}
                        </p>
                    </div>
                </div>
            </div>

            {/* Editor Form */}
            <form onSubmit={handleSubmit} className="space-y-6">

                <div className="bg-zinc-900/60 border border-white/10 rounded-2xl p-6 md:p-8 space-y-6 backdrop-blur-sm">
                    {/* Title */}
                    <div className="space-y-2">
                        <label htmlFor="title" className="block text-sm font-medium text-gray-300">
                            Post Title *
                        </label>
                        <input
                            type="text"
                            id="title"
                            name="title"
                            value={formData.title}
                            onChange={handleChange}
                            required
                            placeholder="e.g., The Future of AI in Options Trading"
                            className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-gray-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all font-semibold"
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Category */}
                        <div className="space-y-2">
                            <label htmlFor="category" className="block text-sm font-medium text-gray-300">
                                Category *
                            </label>
                            <input
                                type="text"
                                id="category"
                                name="category"
                                value={formData.category}
                                onChange={handleChange}
                                required
                                placeholder="e.g., Market Analysis"
                                className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-gray-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm"
                            />
                        </div>

                        {/* Read Time */}
                        <div className="space-y-2">
                            <label htmlFor="readTime" className="block text-sm font-medium text-gray-300">
                                Read Time
                            </label>
                            <input
                                type="text"
                                id="readTime"
                                name="readTime"
                                value={formData.readTime}
                                onChange={handleChange}
                                placeholder="e.g., 5 min read"
                                className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-gray-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm"
                            />
                        </div>
                    </div>

                    {/* Excerpt */}
                    <div className="space-y-2">
                        <label htmlFor="excerpt" className="block text-sm font-medium text-gray-300">
                            Short Excerpt *
                        </label>
                        <textarea
                            id="excerpt"
                            name="excerpt"
                            value={formData.excerpt}
                            onChange={handleChange}
                            required
                            rows={2}
                            placeholder="A brief summary of the article (appears on cards)..."
                            className="w-full bg-black/50 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-gray-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm resize-none"
                        />
                    </div>

                    {/* Image URL */}
                    <div className="space-y-2">
                        <label htmlFor="image" className="block text-sm font-medium text-gray-300">
                            Featured Image URL *
                        </label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-gray-500">
                                <FaImage />
                            </div>
                            <input
                                type="url"
                                id="image"
                                name="image"
                                value={formData.image}
                                onChange={handleChange}
                                required
                                placeholder="https://images.unsplash.com/photo-..."
                                className="w-full bg-black/50 border border-white/10 rounded-xl pl-12 pr-4 py-3 text-white placeholder:text-gray-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm"
                            />
                        </div>
                        {formData.image && (
                            <div className="mt-4 rounded-xl overflow-hidden border border-white/10 aspect-video max-w-sm">
                                <img src={formData.image} alt="Preview" className="w-full h-full object-cover" onError={(e) => (e.currentTarget.style.display = 'none')} />
                            </div>
                        )}
                    </div>

                    {/* Content (Rich Text) */}
                    <div className="space-y-2 pt-4 border-t border-white/5">
                        <div className="flex items-center justify-between mb-2">
                            <label htmlFor="content" className="block text-sm font-medium text-gray-300">
                                Main Content *
                            </label>
                            <div className="flex items-center gap-2 text-xs text-gray-500 bg-white/5 px-2 py-1 rounded border border-white/5">
                                <FaAlignLeft /> Rich Text Editor
                            </div>
                        </div>
                        <div className="text-white min-h-[300px]">
                            <ReactQuill
                                theme="snow"
                                value={formData.content}
                                onChange={handleContentChange}
                                className="bg-black/50 border border-white/10 rounded-xl overflow-hidden [&_.ql-toolbar]:border-white/10 [&_.ql-toolbar]:bg-zinc-900/80 [&_.ql-container]:border-none [&_.ql-editor]:min-h-[300px] [&_.ql-editor]:text-gray-300 [&_.ql-stroke]:stroke-gray-400 hover:[&_.ql-stroke]:stroke-cyan-400 [&_.ql-fill]:fill-gray-400 hover:[&_.ql-fill]:fill-cyan-400 [&_.ql-picker-label]:text-gray-400 [&_.ql-active_.ql-stroke]:stroke-cyan-500 [&_.ql-active_.ql-fill]:fill-cyan-500"
                                placeholder="Write your content here..."
                            />
                        </div>
                    </div>
                </div>

                {/* Submit Actions */}
                <div className="flex justify-end gap-4">
                    <Link
                        to="/admin/dashboard"
                        className="px-6 py-3 rounded-xl border border-white/10 text-white hover:bg-white/5 transition-all font-medium"
                    >
                        Cancel
                    </Link>
                    <button
                        type="submit"
                        disabled={isLoading}
                        className="px-8 py-3 rounded-xl bg-cyan-500 text-black font-bold hover:bg-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.2)] hover:shadow-[0_0_25px_rgba(6,182,212,0.4)] transition-all flex items-center justify-center gap-2 min-w-[150px] disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {isLoading ? (
                            <AiOutlineLoading3Quarters className="animate-spin text-lg" />
                        ) : (
                            <>
                                <FaSave /> {isEditing ? 'Save Changes' : 'Publish Post'}
                            </>
                        )}
                    </button>
                </div>
            </form>
        </div>
    );
};

export default BlogEditor;
